        sentence = grouped_parts[0] + "."
    elif len(grouped_parts) == 2:
        sentence = grouped_parts[0] + ", and " + grouped_parts[1] + "."
    else:
        # Create a more complex sentence with relative clauses
        sentence = grouped_parts[0]
        for i, part in enumerate(grouped_parts[1:], 1):
            if i == len(grouped_parts) - 1:
                sentence += ", and " + part
            else:
                sentence += "; " + part
        sentence += "."

    # Ensure the first character is capitalised
    if sentence:
        sentence = sentence[0].upper() + sentence[1:]
    return sentence

